func TestActionNames(t *testing.T) {

	reg := makeRegistry(t)
	names := []string{
		"service.disable",
		"service.enable",
		"service.restart",
		"service.start",
		"service.stop",
		"service.enabled",
		"service.exists",
		"service.running",
	}
	for _, name := range names {
		a := getAction(t, reg, name)
		if got := a.Name(); got != name {
			t.Errorf("Name() = %q, want %q", got, name)
		}
	}
}

